      addr_hit[21]: begin
        reg_rdata_next[0] = sw_rst_ctrl_n_2_qs;
      end

      addr_hit[22]: begin
        reg_rdata_next[0] = sw_rst_ctrl_n_3_qs;
      end

      addr_hit[23]: begin
        reg_rdata_next[0] = sw_rst_ctrl_n_4_qs;
      end

      addr_hit[24]: begin
        reg_rdata_next[0] = sw_rst_ctrl_n_5_qs;
